#include <iostream>
using namespace std;

class Vector2 {
public:
    double x;
    double y;

    // Конструктор
    Vector2(double x_val = 0, double y_val = 0) : x(x_val), y(y_val) {}

    // --- ПЕРЕВАНТАЖЕННЯ ОПЕРАТОРА ДОДАВАННЯ (+) ---
    // Метод приймає ПРАВУ частину (b) у виразі (a + b)
    Vector2 operator+(const Vector2& rightsS) const {
        return Vector2(this->x + rightsS.x, this->y + rightsS.y);
    }

    // --- ПЕРЕВАНТАЖЕННЯ ВІДНІМАННЯ (-) ---
    Vector2 operator-(const Vector2& r) const {
        return Vector2(this->x - r.x, this->y - r.y);
    }

    // --- ПЕРЕВАНТАЖЕННЯ ПОРІВНЯННЯ (==) ---
    bool operator==(const Vector2& r) const {
        // Вважаємо їх однаковими, якщо координати повністю ідентичні
        if (this->x == r.x && this->y == r.y) return true;
        return false;
    }

    void show() const {
        cout << "(" << x << "; " << y << ")" << endl;
    }
};

int main() {
    Vector2 pos1(10, 20); // Поточна позиція гравця
    Vector2 move(5, -2);  // Вектор руху (швидкість)

    cout << "Старт гравця: "; pos1.show();
    cout << "Дія: додаємо рух + (5; -2)." << endl;

    // 🏆 МАГІЯ! Додаємо два об'єкти мовби це прості числа!
    // Під капотом це викликає pos1.operator+(move)
    Vector2 result = pos1 + move; 

    cout << "Нова позиція: "; result.show();

    // Порівняння ==
    Vector2 vA(5, 5);
    Vector2 vB(5, 5);
    Vector2 vC(0, 0);

    if (vA == vB) cout << "vA та vB ідентичні!" << endl;
    if (!(vA == vC)) cout << "vA та vC різні!" << endl;

    return 0;
}
